var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"어찌저찌 함선에 침투하는 것까지는 성공했나?","JPN":"なんとか艦船に浸透することまでは成功したか？","ENG":"Phew. I managed to infiltrate the ship somehow.","TWN":"我這算成功潛入艦船了？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"으으, 더럽게 춥네. 우주복은 도약 중에 불타버렸나?","JPN":"うう、くそ寒い。宇宙服は跳躍の途中に燃えちゃったか。","ENG":"Ugh, it's so cold in here. Did my spacesuit burn off while I was jumping?","TWN":"呼，好冷啊。太空裝在跳躍過程中被燒毀了嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"잠깐, 우주복이 없는데도 호흡에 문제가 없다는 건…….","JPN":"待てよ、宇宙服がないのに呼吸ができるってことは……","ENG":"Wait, I can breathe without a spacesuit on. That means...","TWN":"等等，沒有太空裝也能呼吸……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"설마 함선 내부에 산소가 공급된다는 건가?","JPN":"まさか、艦船内に酸素が供給されているのか？","ENG":"the ship is supplied with oxygen?","TWN":"這說明艦船內部有氧氣供應？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"대체 이 함선은 뭐야? 무슨 외계인이라도 타고 있는 거야?","JPN":"この艦船、いったい何だ？　宇宙人でも乗っているのか？","ENG":"What is this ship? Are aliens on board or something?","TWN":"那這艘艦船到底是誰的？外星人嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"……음?","JPN":"……ん？","ENG":"...Hmm?","TWN":"……嗯？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>범인류 이민선 사도 시무르그 AI 온라인.</color>","JPN":"<color=#ff3636>汎人類移民船使徒シムルグAIオンライン。</color>","ENG":"<color=#ff3636>Exodus Fleet of Humankind, Apostle Simurgh AI, online.</color>","TWN":"<color=#ff3636>人類移民船使徒西摩格AI已上線。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L18_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>경고. 이민선 내에 선별되지 않은 인원 확인.</color>","JPN":"<color=#ff3636>警告。移民船内に選別されていない人員を確認。</color>","ENG":"<color=#ff3636>Warning. Unauthorized personnel on board the Exodus Fleet.</color>","TWN":"<color=#ff3636>警告。移民船內發現未經篩查的人員。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>강제 퇴거 조치를 위한 단계적 보안 프로토콜을 실행합니다.</color>","JPN":"<color=#ff3636>強制退去措置のための段階的保安プロトコルを実行します。</color>","ENG":"<color=#ff3636>Initiating tiered security protocol for forced evictions.</color>","TWN":"<color=#ff3636>即將實施強制驅逐的分層安全協議。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L22_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"범인류 이민선 사도 시무르그……?","JPN":"汎人類移民船使徒シムルグ……？","ENG":"Exodus Fleet of Humankind, Apostle Simurgh?","TWN":"人類移民船使徒西摩格……？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"사도라면 설마? 클리포트 마왕의……?","JPN":"使徒って、まさか？　クリフォト魔王の……？","ENG":"Apostle? Could it mean the Qliphoth Demon Lord's...?","TWN":"使徒？難道指的是逆卡巴拉魔王的……？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROBO_NPC_NULL_MOON","text":{"KOREA":"<color=#ff3636>프로토콜 확인.</color>","JPN":"<color=#ff3636>プロトコル確認。</color>","ENG":"<color=#ff3636>Protocol confirmed.</color>","TWN":"<color=#ff3636>確認協議。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROBO_NPC_NULL_MOON","text":{"KOREA":"<color=#ff3636>가디언, 적성 개체를 제거한다.</color>","JPN":"<color=#ff3636>ガーディアン、敵性個体を除去する。</color>","ENG":"<color=#ff3636>Guardian, eliminating hostile entity.</color>","TWN":"<color=#ff3636>守護者，清除敵對物體。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이 자식들, 관제 시설에서 봤던 녀석들이잖아!","JPN":"こいつら、管制施設で見たやつらじゃないか！","ENG":"Those bastards...! Those are the things I saw back at the control facility!","TWN":"這些傢伙就是我在控制設施看到的那些！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그래, 이제 확실해졌어.","JPN":"そうか、これで確実になった。","ENG":"Okay, now it all makes sense.","TWN":"很好，現在可以確定了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"관리국의 관제 시설을 공격한 것도, 관리국의 전략위성을 정보오염 시킨 것도.","JPN":"管理局の管制施設を攻撃したのも、管理局の戦略衛星を情報汚染させたのも。","ENG":"The attack on the Administration's control facility, the data corruption of the Administration's strategic satellite,","TWN":"攻擊管理局的控制設施，污染戰略衛星。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"야크샤의 함선을 요격해서 전대원들을 다치게 한 것도.","JPN":"ヤクシャーの艦船を攻撃して戦隊員たちに怪我をさせたのも。","ENG":"intercepting Yaksha's ship and injuring my members,","TWN":"攔截夜叉的艦船，擊傷艦內隊員。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"다이브를 저지해서 필하모닉 홀의 전대원들을 위험에 빠트린 것도.","JPN":"ダイブを阻止してフィルハーモニーホールの戦隊員を危険に陥れたのも。","ENG":"and putting everyone in Philharmonic Hall in danger by preventing them from diving.","TWN":"阻止躍入，將管弦樂廳的隊員們置於危險之中。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"전부 이 빌어먹을 고철 덩어리가 원흉이었던 거야……!!","JPN":"このくそ鉄くずがすべての元凶だったんだ……！！","ENG":"It's all because of this stupid scrap metal...!","TWN":"這一切的罪魁禍首就是這塊該死的廢鐵……！！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROBO_NPC_NULL_MOON","text":{"KOREA":"<color=#ff3636>CRF 검출.</color>","JPN":"<color=#ff3636>CRF検出。</color>","ENG":"<color=#ff3636>CRF detected.</color>","TWN":"<color=#ff3636>檢測到CRF。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROBO_NPC_NULL_MOON","text":{"KOREA":"<color=#ff3636>대인 살상 용도로 주무장을 교체합니다.</color>","JPN":"<color=#ff3636>対人殺傷用途に主武装を交替します。</color>","ENG":"<color=#ff3636>Changing to anti-personnel weapon loadout.</color>","TWN":"<color=#ff3636>更換對人殺傷型主武裝。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"젠장, 사도든 뭐든 내가 알게 뭐야!","JPN":"くそ、使徒も何も、アタシの知ったことじゃない！","ENG":"Crap. Apostle or not, I don't care!","TWN":"可惡，管他什麼使徒！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"1초라도 빨리 함선의 동력원을 파괴하고 지휘부에 알려야 한다고!","JPN":"1秒でも早く艦船の動力源を破壊し、司令部に知らせなくちゃ！","ENG":"All I need to do is destroy the ship's power source as quickly as I can and report back to the Headquarters!","TWN":"我必須儘快摧毀艦船的動力源，通知指揮部！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"아베스타 드라이브는 기본원리는 주위 침식파를 흡수하여 동력으로 환원하는 것…….","JPN":"アヴェスター・ドライブの基本原理は、周りの侵食波を吸収して動力に還元すること……","ENG":"Avesta Drive was made to absorb surrounding Corruption rays as its power source...","TWN":"阿貝斯塔引擎的基本原理是吸收周圍的侵蝕波並將其轉化為動力……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"이건 원래 침식 내성이 강한 기계에 탑재할 것을 전제로 만들어진 물건인 겁니다요.","JPN":"これは本来、侵食耐性の強い機械に搭載することを前提で作られたものでやんす。","ENG":"So it was originally designed to be mounted on machines with strong resistance to Corruption.","TWN":"最初創造它的假設是將它搭載在具有強侵蝕耐性的機器上。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"동일한 원리를 가진 아스트라 드라이브 역시 인간이 사용하기에는 다소 부적절합니다요.","JPN":"同じ原理を持つアストラ・ドライブも、人間が使うにはちょっぴり不適切でやんす。","ENG":"Astra Drive uses the same principle, and it might be unsuitable for human use.","TWN":"採用同樣原理的艾斯特拉引擎，不太適合人類使用。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"침식 내성이 강한 전대장님이라고 해도 두 번 정도가 한계인 겁니다요.","JPN":"侵食耐性の強い戦隊長だとしても、おそらく2回が限界でやんす。","ENG":"Even if your Corruption resistance is strong, one or two uses would be the limit.","TWN":"即使是耐侵蝕性強大的戰隊長，啟動第二次也已經是極限了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"함선 내부에서 침식파가 느껴져.","JPN":"艦船内部から侵食波が感じられる。","ENG":"I can feel the Corruption ray from inside the ship.","TWN":"艦船內可以感受到侵蝕波。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그렇다는 말은 이 녀석들의 동력원은 전부 아베스타 드라이브라는 뜻이겠지.","JPN":"ってことは、こいつらの動力源は全部アヴェスター・ドライブってことだろうな。","ENG":"That means that their power source must be all Avesta Drives.","TWN":"說明這些傢伙的動力源都來自於阿貝斯塔引擎。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그럼 함선의 동력원 위치는 침식파가 가장 강한 곳이 틀림없어……!!","JPN":"じゃあ、艦船の動力源は侵食波がもっとも強い場所にあるはず……！！","ENG":"Then, the location of the power source should be where the Corruption rays are the strongest...!","TWN":"那麼，艦船的動力源所在的位置一定是侵蝕波最強的地方……！！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"여기까지 왔는데 망설일 필요는 없겠지.","JPN":"ここまで来たんだ。もう迷いは必要ない。","ENG":"I've come this far, so there's no need to hesitate now.","TWN":"已經走到了這一步，就不必再猶豫了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"좋아! 믿고 있다고, 쥐스틴!","JPN":"よし！　信じてるよ、ジュスティーヌ！","ENG":"Okay! I knew you'd pull through, Justine!","TWN":"好！我就相信你吧，潔絲婷！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>아스트라 드라이브</color> 기동!","JPN":"<color=#ffd34c>アストラ・ドライブ</color>起動！","ENG":"<color=#ffd34c>Astra Drive</color> activate!","TWN":"<color=#ffd34c>艾斯特拉引擎</color>啟動！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"크아아아아아아아아아아────!!","JPN":"くああああああああああ────！！","ENG":"KRRRRRAAAAGH!!","TWN":"咳啊啊啊……！！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};